#!/usr/bin/env python3

import argparse
import os
import shutil
import subprocess
import sys
import zipfile
from pathlib import Path


def run(cmd, cwd=None):
    print(f"+ {' '.join(cmd)}", flush=True)
    subprocess.run(cmd, cwd=cwd, check=True)


def find_python():
    return sys.executable or "python"


def install_dependencies(python):
    requirements = Path("requirements.txt")
    if requirements.exists():
        run([python, "-m", "pip", "install", "--disable-pip-version-check", "-r", str(requirements)])
    else:
        print("requirements.txt not found, skipping dependency installation.", flush=True)


def run_tests(python):
    if Path("pytest.ini").exists() or Path("conftest.py").exists() or Path("tests").exists():
        run([python, "-m", "pytest", "-q"])
    else:
        print("No test configuration detected, skipping tests.", flush=True)


def should_exclude(path: Path):
    excluded_parts = {
        ".git",
        ".hg",
        ".svn",
        ".mypy_cache",
        ".pytest_cache",
        "__pycache__",
        ".venv",
        "venv",
        "env",
        ".env",
        "build",
        "dist",
        ".idea",
        ".vscode",
        "node_modules",
    }
    excluded_suffixes = {".pyc", ".pyo", ".pyd"}
    return any(part in excluded_parts for part in path.parts) or path.suffix in excluded_suffixes


def package(output_name="deployment_package.zip"):
    root = Path(".").resolve()
    output = root / output_name
    if output.exists():
        output.unlink()

    with zipfile.ZipFile(output, "w", compression=zipfile.ZIP_DEFLATED) as zf:
        for path in root.rglob("*"):
            if path.is_file() and path != output and not should_exclude(path):
                arcname = path.relative_to(root)
                zf.write(path, arcname)

    print(f"Created package: {output}", flush=True)


def clean():
    for name in ("build", "dist"):
        path = Path(name)
        if path.exists():
            shutil.rmtree(path)
    for path in Path(".").rglob("__pycache__"):
        if path.is_dir():
            shutil.rmtree(path, ignore_errors=True)


def main():
    parser = argparse.ArgumentParser(description="Simple CI/CD deployment automation script.")
    parser.add_argument("--skip-tests", action="store_true", help="Skip running tests.")
    parser.add_argument("--output", default="deployment_package.zip", help="Output package filename.")
    args = parser.parse_args()

    python = find_python()
    clean()
    install_dependencies(python)
    if not args.skip_tests:
        run_tests(python)
    package(args.output)


if __name__ == "__main__":
    main()